// worker-public.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    try {
      if (path.startsWith('/api/users')) {
        return await env.USER_SERVICE.fetch(request);
      } else if (path.startsWith('/api/products')) {
        return await env.PRODUCT_SERVICE.fetch(request);
      } else if (path.startsWith('/api/orders')) {
        return await env.ORDER_SERVICE.fetch(request);
      } else if (path.startsWith('/api/analytics')) {
        return await env.ANALYTICS_SERVICE.fetch(request);
      } else {
        return new Response(JSON.stringify({
          error: 'Not Found',
          message: 'The requested endpoint does not exist'
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Internal Server Error',
        message: error.message
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

// worker-user-service.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    const routes = {
      'GET /api/users': async () => {
        const users = await env.DB.prepare('SELECT * FROM users').all();
        return new Response(JSON.stringify(users.results), {
          headers: { 'Content-Type': 'application/json' }
        });
      },
      'GET /api/users/:id': async () => {
        const userId = path.split('/').pop();
        const user = await env.DB.prepare('SELECT * FROM users WHERE id = ?').bind(userId).first();
        
        if (!user) {
          return new Response(JSON.stringify({ error: 'User not found' }), {
            status: 404,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        const analyticsRequest = new Request('http://internal/track', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            event: 'user_viewed',
            userId: userId,
            timestamp: Date.now()
          })
        });
        ctx.waitUntil(env.ANALYTICS_SERVICE.fetch(analyticsRequest));

        return new Response(JSON.stringify(user), {
          headers: { 'Content-Type': 'application/json' }
        });
      },
      'POST /api/users': async () => {
        const body = await request.json();
        const { name, email } = body;

        if (!name || !email) {
          return new Response(JSON.stringify({ error: 'Name and email are required' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        const result = await env.DB.prepare('INSERT INTO users (name, email) VALUES (?, ?)').bind(name, email).run();

        const analyticsRequest = new Request('http://internal/track', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            event: 'user_created',
            userId: result.meta.last_row_id,
            timestamp: Date.now()
          })
        });
        ctx.waitUntil(env.ANALYTICS_SERVICE.fetch(analyticsRequest));

        return new Response(JSON.stringify({
          id: result.meta.last_row_id,
          name,
          email
        }), {
          status: 201,
          headers: { 'Content-Type': 'application/json' }
        });
      },
      'PUT /api/users/:id': async () => {
        const userId = path.split('/').pop();
        const body = await request.json();
        const { name, email } = body;

        await env.DB.prepare('UPDATE users SET name = ?, email = ? WHERE id = ?').bind(name, email, userId).run();

        return new Response(JSON.stringify({
          id: userId,
          name,
          email
        }), {
          headers: { 'Content-Type': 'application/json' }
        });
      },
      'DELETE /api/users/:id': async () => {
        const userId = path.split('/').pop();
        await env.DB.prepare('DELETE FROM users WHERE id = ?').bind(userId).run();

        return new Response(JSON.stringify({ success: true }), {
          headers: { 'Content-Type': 'application/json' }
        });
      }
    };

    const routeKey = path.includes('/api/users/') && path.split('/').length > 3
      ? `${method} /api/users/:id`
      : `${method} ${path}`;

    if (routes[routeKey]) {
      return await routes[routeKey]();
    }

    return new Response(JSON.stringify({ error: 'Route not found' }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' }
    });
  }
};

